import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ThemeProvider } from './context/ThemeContext';

import HomePage from './pages/HomePage';
import LoginPage from './pages/auth/LoginPage';
import SignupPage from './pages/auth/SignupPage';
import UserDashboard from './pages/user/UserDashboard';
import AdminPanel from './pages/admin/AdminPanel';
import BooksPage from './pages/admin/BooksPage';
import MembersPage from './pages/admin/MembersPage';
import IssuesPage from './pages/admin/IssuesPage';
import UsersPage from './pages/admin/UsersPage';
import DashboardHome from './pages/admin/DashboardHome';

const ProtectedRoute = ({ children, adminRequired }) => {
  const { user, loading } = useAuth();
  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh', background: 'var(--black)' }}>
      <div className="spinner" />
    </div>
  );
  if (!user) return <Navigate to="/login" replace />;
  if (adminRequired && user.role !== 'admin') return <Navigate to="/dashboard" replace />;
  return children;
};

const PublicRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return null;
  if (user) return <Navigate to={user.role === 'admin' ? '/admin' : '/dashboard'} replace />;
  return children;
};

function AppRoutes() {
  return (
    <Routes>
      <Route path="/" element={<HomePage />} />
      <Route path="/login" element={<PublicRoute><LoginPage /></PublicRoute>} />
      <Route path="/signup" element={<PublicRoute><SignupPage /></PublicRoute>} />
      <Route path="/dashboard" element={<ProtectedRoute><UserDashboard /></ProtectedRoute>} />
      <Route path="/admin" element={<ProtectedRoute adminRequired><AdminPanel /></ProtectedRoute>}>
        <Route index element={<DashboardHome />} />
        <Route path="books" element={<BooksPage />} />
        <Route path="members" element={<MembersPage />} />
        <Route path="issues" element={<IssuesPage />} />
        <Route path="users" element={<UsersPage />} />
      </Route>
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}

export default function App() {
  return (
    <ThemeProvider>
      <AuthProvider>
        <Router>
          <AppRoutes />
          <Toaster
            position="top-right"
            toastOptions={{
              duration: 3500,
              style: {
                background: 'var(--surface)',
                color: 'var(--text)',
                border: '1px solid rgba(201,168,76,0.3)',
                fontFamily: 'Jost, sans-serif',
                fontSize: '14px',
              },
              success: { iconTheme: { primary: '#c9a84c', secondary: '#1e1e2a' } },
              error: { iconTheme: { primary: '#e05a5a', secondary: '#1e1e2a' } },
            }}
          />
        </Router>
      </AuthProvider>
    </ThemeProvider>
  );
}
